  1→//! Integration tests: real Praxis tools exposed through the MCP server.
  2→//!
  3→//! Tests the full flow: register tools → build MCP server → call_tool/list_tools.
  4→
  5→use aios_protocol::tool::ToolRegistry;
  6→use praxis_core::local_fs::LocalFs;
  7→use praxis_core::workspace::FsPolicy;
  8→use praxis_mcp::server::PraxisMcpServer;
  9→use praxis_tools::fs::{GlobTool, GrepTool, ListDirTool, ReadFileTool, WriteFileTool};
 10→use praxis_tools::memory::{ReadMemoryTool, WriteMemoryTool};
 11→use serde_json::json;
 12→use std::sync::Arc;
 13→use tempfile::TempDir;
 14→
 15→/// Build a PraxisMcpServer with all filesystem and memory tools.
 16→fn server_with_real_tools(workspace: &std::path::Path) -> PraxisMcpServer {
 17→    let policy = FsPolicy::new(workspace);
 18→    let fs = Arc::new(LocalFs::new(policy));
 19→    let memory_dir = workspace.join(".memory");
 20→    std::fs::create_dir_all(&memory_dir).unwrap();
 21→
 22→    let mut registry = ToolRegistry::default();
 23→    registry.register(ReadFileTool::new(fs.clone()));
 24→    registry.register(WriteFileTool::new(fs.clone()));
 25→    registry.register(ListDirTool::new(fs.clone()));
 26→    registry.register(GlobTool::new(fs.clone()));
 27→    registry.register(GrepTool::new(fs));
 28→    registry.register(ReadMemoryTool::new(memory_dir.clone()));
 29→    registry.register(WriteMemoryTool::new(memory_dir));
 30→
 31→    PraxisMcpServer::new(registry)
 32→}
 33→
 34→/// Helper to call a tool on the server synchronously (mimicking MCP call_tool).
 35→///
 36→/// Exercises the same code path as `ServerHandler::call_tool` but without
 37→/// requiring a full transport/peer setup.
 38→fn call_tool(
 39→    server: &PraxisMcpServer,
 40→    tool_name: &str,
 41→    args: serde_json::Value,
 42→) -> rmcp::model::CallToolResult {
 43→    let call = aios_protocol::tool::ToolCall {
 44→        call_id: "test-call".to_string(),
 45→        tool_name: tool_name.to_string(),
 46→        input: args,
 47→        requested_capabilities: vec![],
 48→    };
 49→    let ctx = aios_protocol::tool::ToolContext {
 50→        run_id: "test-run".to_string(),
 51→        session_id: "test-session".to_string(),
 52→        iteration: 0,
 53→    };
 54→
 55→    let registry_tool = server.registry().get(tool_name).unwrap();
 56→    let result = registry_tool.execute(&call, &ctx).unwrap();
 57→    praxis_mcp::convert::tool_result_to_call_result(&result)
 58→}
 59→
 60→#[test]
 61→fn list_tools_returns_all_praxis_tools() {
 62→    let tmp = TempDir::new().unwrap();
 63→    let server = server_with_real_tools(tmp.path());
 64→    let tools = server.mcp_tools();
 65→
 66→    // Should have 7 tools: read_file, write_file, list_dir, glob, grep, read_memory, write_memory
 67→    assert_eq!(tools.len(), 7);
 68→
 69→    let names: Vec<&str> = tools.iter().map(|t| t.name.as_ref()).collect();
 70→    assert!(names.contains(&"read_file"), "missing read_file");
 71→    assert!(names.contains(&"write_file"), "missing write_file");
 72→    assert!(names.contains(&"list_dir"), "missing list_dir");
 73→    assert!(names.contains(&"glob"), "missing glob");
 74→    assert!(names.contains(&"grep"), "missing grep");
 75→    assert!(names.contains(&"read_memory"), "missing read_memory");
 76→    assert!(names.contains(&"write_memory"), "missing write_memory");
 77→}
 78→
 79→#[test]
 80→fn tool_schemas_are_valid_json_objects() {
 81→    let tmp = TempDir::new().unwrap();
 82→    let server = server_with_real_tools(tmp.path());
 83→
 84→    for tool in server.mcp_tools() {
 85→        let schema = tool.input_schema.as_ref();
 86→        assert!(
 87→            schema.contains_key("type"),
 88→            "tool {} input_schema missing 'type'",
 89→            tool.name
 90→        );
 91→        assert_eq!(
 92→            schema.get("type").and_then(|v| v.as_str()),
 93→            Some("object"),
 94→            "tool {} input_schema type must be 'object'",
 95→            tool.name
 96→        );
 97→    }
 98→}
 99→
100→#[test]
101→fn write_and_read_file_through_mcp() {
102→    let tmp = TempDir::new().unwrap();
103→    let server = server_with_real_tools(tmp.path());
104→
105→    // Write a file
106→    let write_result = call_tool(
107→        &server,
108→        "write_file",
109→        json!({
110→            "path": "test.txt",
111→            "content": "hello from MCP"
112→        }),
113→    );
114→    assert_ne!(write_result.is_error, Some(true));
115→
116→    // Read it back
117→    let read_result = call_tool(&server, "read_file", json!({"path": "test.txt"}));
118→    assert_ne!(read_result.is_error, Some(true));
119→
120→    // Verify content appears in the response
121→    let text = read_result
122→        .content
123→        .iter()
124→        .find_map(|c| c.as_text().map(|t| t.text.clone()))
125→        .unwrap_or_default();
126→    assert!(
127→        text.contains("hello from MCP"),
128→        "read_file should return the written content, got: {text}"
129→    );
130→}
