132→#[test]
133→fn list_dir_through_mcp() {
134→    let tmp = TempDir::new().unwrap();
135→    std::fs::write(tmp.path().join("a.txt"), "aaa").unwrap();
136→    std::fs::write(tmp.path().join("b.txt"), "bbb").unwrap();
137→
138→    let server = server_with_real_tools(tmp.path());
