151→#[test]
152→fn glob_finds_files_through_mcp() {
153→    let tmp = TempDir::new().unwrap();
154→    std::fs::write(tmp.path().join("foo.rs"), "fn main() {}").unwrap();
155→    std::fs::write(tmp.path().join("bar.txt"), "text").unwrap();
156→
157→    let server = server_with_real_tools(tmp.path());
