222→#[test]
223→fn server_info_describes_praxis() {
224→    let tmp = TempDir::new().unwrap();
225→    let server = server_with_real_tools(tmp.path());
226→    let info = server.get_info();
227→
228→    assert_eq!(info.server_info.name, "praxis");
