 50→        })
 51→        .collect()
 52→}
 53→
 54→/// Render content with line numbers and hash tags for display.
 55→pub fn render_hashed_content(content: &str) -> String {
 56→    hash_lines(content)
 57→        .into_iter()
 58→        .map(|line| format!("{:>4} {} | {}", line.line_no, line.tag, line.text))
 59→        .collect::<Vec<_>>()
 60→        .join("\n")
 61→}
 62→
 63→/// Apply a sequence of tagged edit operations to content.
 64→pub fn apply_tagged_edits(content: &str, ops: &[TaggedEditOp]) -> Result<String, EditError> {
 65→    let initial_lines = hash_lines(content);
 66→
 67→    if initial_lines.is_empty() && !ops.is_empty() {
 68→        return Err(EditError::EmptyContent);
 69→    }
 70→
 71→    let mut editable: Vec<EditableLine> = initial_lines
 72→        .iter()
 73→        .map(|line| EditableLine {
 74→            anchor_tag: Some(line.tag.clone()),
 75→            text: line.text.clone(),
 76→        })
 77→        .collect();
 78→
 79→    for op in ops {
 80→        match op {
 81→            TaggedEditOp::ReplaceLine { tag, new_text } => {
 82→                let idx = find_anchor_index(&editable, tag)?;
 83→                editable[idx].text = new_text.clone();
 84→            }
 85→            TaggedEditOp::InsertAfterTag { tag, new_text } => {
 86→                let idx = find_anchor_index(&editable, tag)?;
 87→                editable.insert(
 88→                    idx + 1,
 89→                    EditableLine {
 90→                        anchor_tag: None,
 91→                        text: new_text.clone(),
 92→                    },
 93→                );
 94→            }
 95→            TaggedEditOp::DeleteLine { tag } => {
 96→                let idx = find_anchor_index(&editable, tag)?;
 97→                editable.remove(idx);
 98→            }
 99→        }
100→    }
101→
102→    Ok(editable
103→        .into_iter()
104→        .map(|line| line.text)
105→        .collect::<Vec<_>>()
106→        .join("\n"))
107→}
108→
109→fn find_anchor_index(lines: &[EditableLine], tag: &str) -> Result<usize, EditError> {
110→    lines
111→        .iter()
112→        .position(|line| line.anchor_tag.as_deref() == Some(tag))
113→        .ok_or_else(|| EditError::StaleTag(tag.to_string()))
114→}
115→
116→fn line_tag(line_no: usize, text: &str) -> String {
117→    let mut hasher = Hasher::new();
118→    hasher.update(line_no.to_string().as_bytes());
119→    hasher.update(b":");
120→    hasher.update(text.as_bytes());
121→    let digest = hasher.finalize().to_hex().to_string();
122→    digest.chars().take(8).collect()
123→}
124→
125→/// Errors from the hashline editing system.
126→#[derive(Debug, Error)]
127→pub enum EditError {
128→    #[error("input content is empty; tags are required before edit")]
129→    EmptyContent,
130→    #[error("tag is stale or missing in current content: {0}")]
131→    StaleTag(String),
132→}
