134→// ── EditFileTool ──────────────────────────────────────────────────────
135→
136→/// Tool that applies hashline edits to files.
137→pub struct EditFileTool {
138→    fs: Arc<dyn FsPort>,
139→}
140→
141→impl EditFileTool {
142→    pub fn new(fs: Arc<dyn FsPort>) -> Self {
143→        Self { fs }
144→    }
145→}
146→
147→impl Tool for EditFileTool {
148→    fn definition(&self) -> ToolDefinition {
149→        ToolDefinition {
150→            name: "edit_file".into(),
151→            description: "Edits a file using line tags. Operations: replace_line, insert_after_tag, delete_line.".into(),
152→            input_schema: json!({
153→                "type": "object",
154→                "properties": {
155→                    "path": { "type": "string", "description": "Path to the file" },
156→                    "ops": {
157→                        "type": "array",
158→                        "items": {
159→                            "type": "object",
160→                            "oneOf": [
161→                                { "properties": { "op": { "const": "replace_line" }, "tag": { "type": "string" }, "new_text": { "type": "string" } }, "required": ["op", "tag", "new_text"] },
162→                                { "properties": { "op": { "const": "insert_after_tag" }, "tag": { "type": "string" }, "new_text": { "type": "string" } }, "required": ["op", "tag", "new_text"] },
163→                                { "properties": { "op": { "const": "delete_line" }, "tag": { "type": "string" } }, "required": ["op", "tag"] }
164→                            ]
165→                        }
166→                    }
167→                },
168→                "required": ["path", "ops"]
169→            }),
170→            title: Some("Edit File".into()),
171→            output_schema: None,
172→            annotations: Some(ToolAnnotations {
173→                destructive: true,
174→                ..Default::default()
175→            }),
176→            category: Some("filesystem".into()),
177→            tags: vec!["fs".into(), "edit".into()],
178→            timeout_secs: Some(30),
179→        }
180→    }
181→
182→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
183→        let path_str = call
184→            .input
185→            .get("path")
186→            .and_then(|v| v.as_str())
187→            .ok_or_else(|| ToolError::InvalidInput {
188→                message: "Missing or invalid 'path' argument".into(),
189→            })?;
190→
191→        let ops_value = call
192→            .input
193→            .get("ops")
194→            .ok_or_else(|| ToolError::InvalidInput {
195→                message: "Missing 'ops' argument".into(),
196→            })?;
197→
198→        let ops: Vec<TaggedEditOp> =
199→            serde_json::from_value(ops_value.clone()).map_err(|e| ToolError::InvalidInput {
200→                message: format!("Invalid 'ops' format: {e}"),
201→            })?;
202→
203→        let span = tracing::info_span!(
204→            "edit_file",
205→            hashline.file = %path_str,
206→            hashline.ops_count = ops.len(),
207→            hashline.lines_changed = tracing::field::Empty,
208→        );
209→        let _guard = span.enter();
210→
211→        let path = self
212→            .fs
213→            .resolve_for_write(Path::new(path_str))
214→            .map_err(|e| ToolError::PolicyViolation {
215→                message: e.to_string(),
216→            })?;
217→
218→        let content = self
219→            .fs
220→            .read_to_string(&path)
221→            .map_err(|e| ToolError::ExecutionFailed {
222→                tool_name: "edit_file".into(),
223→                message: format!("Failed to read file: {e}"),
224→            })?;
225→
226→        let original_line_count = content.lines().count();
227→
228→        let new_content =
229→            apply_tagged_edits(&content, &ops).map_err(|e| ToolError::ExecutionFailed {
230→                tool_name: "edit_file".into(),
231→                message: format!("Edit failed: {e}"),
232→            })?;
233→
234→        let new_line_count = new_content.lines().count();
235→        let lines_changed = (new_line_count as isize - original_line_count as isize).unsigned_abs();
236→        span.record("hashline.lines_changed", lines_changed);
237→
238→        self.fs
239→            .write(&path, new_content.as_bytes())
240→            .map_err(|e| ToolError::ExecutionFailed {
241→                tool_name: "edit_file".into(),
242→                message: format!("Failed to write file: {e}"),
243→            })?;
244→
245→        info!(ops = ops.len(), lines_changed, "file edited");
246→
247→        let hashed_content = render_hashed_content(&new_content);
248→
249→        Ok(ToolResult {
250→            call_id: call.call_id.clone(),
251→            tool_name: call.tool_name.clone(),
252→            output: json!({ "success": true, "content": hashed_content, "path": path }),
253→            content: None,
254→            is_error: false,
255→        })
256→    }
257→}
